sql:
SELECT MAX(log_time) AS most_recent_log_time 
FROM logs 
WHERE tenant_id = 'your_tenant_id';

SELECT tenants.tenant_name, tenants.description, devices.device_name, devices.device_type
FROM tenants
INNER JOIN devices ON tenants.tenant_id = devices.tenant_id;

SELECT COUNT(policy_id) AS active_policies
FROM security_policies
WHERE tenant_id = 'tenant1' AND is_active = 1;

SELECT logs.* 
FROM logs
WHERE logs.tenant_id = 'specific_tenant_id';

SELECT policy_name 
FROM security_policies 
WHERE tenant_id = 'tenant1' AND priority > 5;

SELECT se.event_id, se.event_type, se.event_description, SUM(se.impact_score) as total_impact_score
FROM security_events se
GROUP BY se.event_id, se.event_type, se.event_description;
